'use client';

import { useState, useEffect } from 'react';
import { useRouter, useParams } from 'next/navigation';
import { useAuth } from '@/context/AuthContext';
import { doc, getDoc, updateDoc, arrayUnion } from 'firebase/firestore';
import { db } from '@/lib/firebase';
import { Project } from '@/lib/types';
import { motion } from 'framer-motion';
import { HiOutlineArrowLeft, HiOutlineSparkles, HiOutlineCheck } from 'react-icons/hi';
import Avatar from '@/components/Avatar';

interface RankedCandidate {
    uid: string;
    rank: number;
    justification: string;
    concerns: string | null;
    metadata: any;
    score: number;
}

export default function ProjectMatchesPage() {
    const { user, loading } = useAuth();
    const router = useRouter();
    const params = useParams();
    const projectId = params.id as string;

    const [project, setProject] = useState<Project | null>(null);
    const [candidates, setCandidates] = useState<RankedCandidate[]>([]);
    const [isSearching, setIsSearching] = useState(true);
    const [invitingMsg, setInvitingMsg] = useState<string | null>(null);

    useEffect(() => {
        if (!loading && !user) router.push('/auth');
    }, [user, loading, router]);

    useEffect(() => {
        const fetchMatches = async () => {
            if (!projectId) return;
            try {
                const prodDoc = await getDoc(doc(db, 'projects', projectId));
                if (!prodDoc.exists()) throw new Error('Project not found');
                const pData = { id: prodDoc.id, ...prodDoc.data() } as Project & { _requirements?: any };
                setProject(pData);

                if (pData.ownerId !== user?.uid) {
                    router.push(`/projects/${projectId}`);
                    return;
                }

                // 1. Vector Search Candidates
                // Fallback to project description if NIM hasn't processed requirements yet
                const projectText = pData._requirements?.enhanced_description
                    || `${pData.name}. ${pData.description}. Needs: ${pData.tags?.join(', ')}`;

                const searchRes = await fetch('/api/pinecone', {
                    method: 'POST',
                    headers: { 'Content-Type': 'application/json' },
                    body: JSON.stringify({
                        action: 'search-candidates',
                        payload: { projectText, topK: 15 },
                    }),
                });
                const searchData = await searchRes.json();

                if (!searchData.matches || searchData.matches.length === 0) {
                    setIsSearching(false);
                    return;
                }

                // 2. Rerank using NIM
                const rerankRes = await fetch('/api/nim', {
                    method: 'POST',
                    headers: { 'Content-Type': 'application/json' },
                    body: JSON.stringify({
                        action: 'rerank-candidates',
                        payload: {
                            candidates: searchData.matches,
                            projectContext: projectText,
                            topK: 10,
                        },
                    }),
                });
                const rerankData = await rerankRes.json();
                const rankedMatches: RankedCandidate[] = (rerankData.ranked || []).map((r: any) => {
                    const original = searchData.matches.find((m: any) => m.uid === r.uid);
                    return { ...r, metadata: original?.metadata || {}, score: original?.score || 0 };
                });

                // Fallback if NIM failed to rerank but Pinecone worked
                if (rankedMatches.length === 0) {
                    setCandidates(searchData.matches.map((m: any, i: number) => ({
                        uid: m.uid,
                        rank: i + 1,
                        justification: 'Matched based on shared keywords and semantic profile similarity.',
                        concerns: null,
                        metadata: m.metadata,
                        score: m.score
                    })));
                } else {
                    setCandidates(rankedMatches);
                }

            } catch (err) {
                console.error('Error fetching matches:', err);
            } finally {
                setIsSearching(false);
            }
        };
        if (user) fetchMatches();
    }, [projectId, user, router]);

    const handleInvite = async (uid: string) => {
        if (!project) return;
        setInvitingMsg(uid);
        try {
            // Add the user to the interested list silently, or we could automatically approve them.
            // For now, let's treat "Invite" as automatically adding them to interestedUsers
            // so they show up on the main project dashboard.
            await updateDoc(doc(db, 'projects', project.id), {
                interestedUsers: arrayUnion(uid),
            });
            // Optionally create a chat thread directly, but let's keep it simple.
        } catch (error) {
            console.error('Error inviting user:', error);
        } finally {
            setTimeout(() => setInvitingMsg(null), 1000);
        }
    };

    if (loading || isSearching) {
        return (
            <div className="min-h-screen flex flex-col items-center justify-center bg-white px-6 text-center space-y-6">
                <motion.div
                    animate={{ scale: [1, 1.2, 1], rotate: [0, 180, 360] }}
                    transition={{ repeat: Infinity, duration: 3, ease: 'easeInOut' }}
                    className="w-16 h-16 bg-black rounded-2xl flex items-center justify-center shadow-2xl"
                >
                    <HiOutlineSparkles className="text-white text-3xl" />
                </motion.div>
                <div>
                    <h2 className="text-xl font-bold tracking-tight mb-2">Finding the right fit...</h2>
                    <p className="text-sm text-gray-500 max-w-xs mx-auto">
                        Nexus AI is scanning the campus network, analyzing working styles, and matching skill vectors.
                    </p>
                </div>
            </div>
        );
    }

    if (!project) return null;

    return (
        <div className="min-h-screen bg-gray-50 pb-20">
            <div className="sticky top-0 bg-white/90 backdrop-blur-lg z-10 border-b border-gray-100">
                <div className="max-w-xl mx-auto px-4 py-4 flex items-center gap-3">
                    <button
                        onClick={() => router.back()}
                        className="w-8 h-8 flex items-center justify-center rounded-full hover:bg-gray-100 transition-colors"
                    >
                        <HiOutlineArrowLeft className="text-lg" />
                    </button>
                    <div>
                        <h1 className="text-lg font-bold tracking-tight">AI Matches</h1>
                        <p className="text-xs text-gray-400">for {project.name}</p>
                    </div>
                </div>
            </div>

            <div className="max-w-xl mx-auto px-4 py-6 space-y-4">
                {candidates.length === 0 ? (
                    <div className="text-center py-10 bg-white rounded-2xl border border-gray-100">
                        <p className="text-sm font-semibold text-gray-600 mb-2">No strong matches found</p>
                        <p className="text-xs text-gray-400 max-w-xs mx-auto">
                            Your project might be highly specialized, or there aren't enough students on the platform yet.
                        </p>
                    </div>
                ) : (
                    candidates.map((candidate, i) => {
                        const isInvited = project.interestedUsers.includes(candidate.uid) || project.approvedUsers.includes(candidate.uid);

                        return (
                            <motion.div
                                key={candidate.uid}
                                initial={{ opacity: 0, y: 20 }}
                                animate={{ opacity: 1, y: 0 }}
                                transition={{ delay: i * 0.1 }}
                                className="bg-white rounded-2xl p-5 shadow-sm border border-gray-100 relative overflow-hidden"
                            >
                                {/* Ranking Badge */}
                                <div className="absolute top-0 right-0 bg-black text-white text-[10px] font-bold px-3 py-1 rounded-bl-xl uppercase tracking-widest">
                                    Match #{candidate.rank}
                                </div>

                                <div className="flex items-start gap-4 mb-4">
                                    <Avatar codeName={candidate.metadata?.codeName || 'Unknown'} size="lg" />
                                    <div className="flex-1 min-w-0 pr-12">
                                        <h3 className="text-base font-bold truncate">
                                            {candidate.metadata?.codeName || 'Anonymous Student'}
                                        </h3>
                                        <p className="text-xs text-gray-500 mb-1 truncate">
                                            {candidate.metadata?.headline || candidate.metadata?.college}
                                        </p>
                                        <div className="flex flex-wrap gap-1 mt-2">
                                            {(candidate.metadata?.hard_skills as string[])?.slice(0, 3).map((skill) => (
                                                <span key={skill} className="px-2 py-0.5 bg-gray-100 text-gray-600 text-[10px] font-medium rounded-sm">
                                                    {skill}
                                                </span>
                                            ))}
                                        </div>
                                    </div>
                                </div>

                                {/* AI Reasoning */}
                                <div className="bg-violet-50/50 rounded-xl p-4 border border-violet-100 mb-4">
                                    <div className="flex items-center gap-1.5 mb-2">
                                        <HiOutlineSparkles className="text-violet-600 text-sm" />
                                        <span className="text-[10px] font-bold uppercase tracking-widest text-violet-700">Why them?</span>
                                    </div>
                                    <p className="text-sm text-gray-800 leading-relaxed">
                                        {candidate.justification}
                                    </p>
                                    {candidate.concerns && (
                                        <p className="text-xs text-gray-500 mt-2 border-t border-violet-100 pt-2">
                                            <span className="font-semibold">Note:</span> {candidate.concerns}
                                        </p>
                                    )}
                                </div>

                                <div className="flex gap-2">
                                    <button
                                        onClick={() => handleInvite(candidate.uid)}
                                        disabled={isInvited || invitingMsg === candidate.uid}
                                        className={`flex-1 py-2.5 rounded-xl text-sm font-semibold flex items-center justify-center gap-2 transition-all ${isInvited
                                                ? 'bg-gray-100 text-gray-400 cursor-not-allowed'
                                                : 'bg-black text-white hover:bg-gray-800'
                                            }`}
                                    >
                                        {isInvited ? (
                                            <>
                                                <HiOutlineCheck /> Requested
                                            </>
                                        ) : invitingMsg === candidate.uid ? (
                                            'Inviting...'
                                        ) : (
                                            'Invite to Project'
                                        )}
                                    </button>
                                    <button className="px-4 py-2.5 bg-gray-50 border border-gray-200 text-gray-600 rounded-xl text-sm font-semibold hover:border-black transition-colors">
                                        View Profile
                                    </button>
                                </div>
                            </motion.div>
                        );
                    })
                )}
            </div>
        </div>
    );
}
